{
  "name": "Smart Initiative Pro",
  "description": "Ứng dụng hỗ trợ viết sáng kiến kinh nghiệm theo chuẩn giáo dục Việt Nam, tích hợp AI để gợi ý nội dung chuyên nghiệp."
}

export interface ReportData {
  location: string;
  day: string;
  month: string;
  year: string;
  title: string;
  author: string;
  unit: string;
  collaborators: string;
  startDate: string;
  endDate: string;
  problemStatement: {
    initiativeName: string;
    necessity: string;
  };
  content: {
    status: {
      advantages: string;
      disadvantages: string;
    };
    causes: string;
    solutions: string;
  };
  evaluation: {
    novelty: string;
    efficiency: string;
    scope: string;
  };
  conclusion: string;
}

export type ActiveSection = 'info' | 'problem' | 'content' | 'evaluation' | 'conclusion';

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateSectionContent = async (sectionName: string, context: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Bạn là một chuyên gia giáo dục tại Việt Nam, có kinh nghiệm viết sáng kiến kinh nghiệm đoạt giải cao.
    Hãy viết nội dung cho phần "${sectionName}" dựa trên bối cảnh: "${context}".

    Yêu cầu:
    1. Ngôn ngữ chuyên nghiệp, đúng văn phong sư phạm Việt Nam.
    2. Nội dung cụ thể, sáng tạo và có tính thực tiễn cao.
    3. Trình bày rõ ràng, mạch lạc.

    Phần cần viết: ${sectionName}
    Bối cảnh/Tên sáng kiến: ${context}

    Kết quả trả về chỉ bao gồm nội dung văn bản cho phần này, không thêm lời dẫn của AI.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        temperature: 0.7,
        topP: 0.9,
      }
    });

    return response.text || "Không thể tạo nội dung, vui lòng thử lại.";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Lỗi kết nối AI. Vui lòng kiểm tra lại.";
  }
};

import React from 'react';

interface SectionHeaderProps {
  title: string;
  description?: string;
}

export const SectionHeader: React.FC<SectionHeaderProps> = ({ title, description }) => (
  <div className="mb-6">
    <h2 className="text-xl font-bold text-slate-800">{title}</h2>
    {description && <p className="text-sm text-slate-500 mt-1">{description}</p>}
  </div>
);

import React from 'react';
import { Sparkles, Loader2 } from 'lucide-react';

interface FormFieldProps {
  label: string;
  value: string;
  onChange: (value: string) => void;
  type?: 'text' | 'textarea';
  onAIGenerate?: () => void;
  isGenerating?: boolean;
  placeholder?: string;
}

export const FormField: React.FC<FormFieldProps> = ({
  label,
  value,
  onChange,
  type = 'text',
  onAIGenerate,
  isGenerating,
  placeholder
}) => (
  <div className="mb-4">
    <div className="flex justify-between items-center mb-1">
      <label className="text-sm font-semibold text-slate-700">{label}</label>
      {onAIGenerate && (
        <button
          onClick={onAIGenerate}
          disabled={isGenerating}
          className="flex items-center gap-1 text-xs font-medium text-indigo-600 hover:text-indigo-700 transition-colors disabled:opacity-50"
        >
          {isGenerating ? (
            <Loader2 className="w-3 h-3 animate-spin" />
          ) : (
            <Sparkles className="w-3 h-3" />
          )}
          Gợi ý bằng AI
        </button>
      )}
    </div>
    {type === 'text' ? (
      <input
        type="text"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
      />
    ) : (
      <textarea
        rows={4}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
      />
    )}
  </div>
);

import React, { useState, useCallback } from 'react';
import { 
  FileText, 
  Printer, 
  ChevronRight, 
  ChevronLeft, 
  Settings, 
  Info, 
  HelpCircle,
  BarChart3,
  CheckCircle2,
  Save
} from 'lucide-react';
import { ReportData, ActiveSection } from './types';
import { FormField } from './components/FormField';
import { SectionHeader } from './components/SectionHeader';
import { ReportPreview } from './components/ReportPreview';
import { generateSectionContent } from './services/geminiService';

const INITIAL_DATA: ReportData = {
  location: 'Rạch Chèo',
  day: '',
  month: '',
  year: new Date().getFullYear().toString(),
  title: '',
  author: '',
  unit: '',
  collaborators: '',
  startDate: '',
  endDate: '',
  problemStatement: {
    initiativeName: '',
    necessity: '',
  },
  content: {
    status: {
      advantages: '',
      disadvantages: '',
    },
    causes: '',
    solutions: '',
  },
  evaluation: {
    novelty: '',
    efficiency: '',
    scope: '',
  },
  conclusion: '',
};

const SECTIONS: { id: ActiveSection; label: string; icon: React.ReactNode }[] = [
  { id: 'info', label: 'Thông tin chung', icon: <Info className="w-4 h-4" /> },
  { id: 'problem', label: 'Đặt vấn đề', icon: <HelpCircle className="w-4 h-4" /> },
  { id: 'content', label: 'Nội dung', icon: <FileText className="w-4 h-4" /> },
  { id: 'evaluation', label: 'Đánh giá', icon: <BarChart3 className="w-4 h-4" /> },
  { id: 'conclusion', label: 'Kết luận', icon: <CheckCircle2 className="w-4 h-4" /> },
];

export default function App() {
  const [data, setData] = useState<ReportData>(INITIAL_DATA);
  const [activeTab, setActiveTab] = useState<ActiveSection>('info');
  const [isGenerating, setIsGenerating] = useState<string | null>(null);

  const handleUpdate = (path: string, value: string) => {
    setData(prev => {
      const newData = { ...prev };
      const keys = path.split('.');
      let current: any = newData;
      for (let i = 0; i < keys.length - 1; i++) {
        current = current[keys[i]];
      }
      current[keys[keys.length - 1]] = value;
      return newData;
    });
  };

  const handleAIGenerate = async (section: string, field: string) => {
    if (!data.title) {
      alert("Vui lòng nhập tên sáng kiến trước khi sử dụng AI.");
      return;
    }

    setIsGenerating(field);
    const content = await generateSectionContent(section, data.title);
    handleUpdate(field, content);
    setIsGenerating(null);
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Top Navbar */}
      <header className="no-print bg-indigo-700 text-white p-4 shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-lg text-indigo-700">
              <FileText className="w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-bold">Smart Initiative Pro</h1>
              <p className="text-xs text-indigo-100">Công cụ soạn thảo Sáng kiến kinh nghiệm 4.0</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={() => alert("Dữ liệu đã được lưu tạm vào trình duyệt!")}
              className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-lg text-sm font-medium transition-colors"
            >
              <Save className="w-4 h-4" />
              Lưu bản nháp
            </button>
            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 bg-white text-indigo-700 hover:bg-indigo-50 px-4 py-2 rounded-lg text-sm font-medium transition-colors"
            >
              <Printer className="w-4 h-4" />
              In / Xuất PDF
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 flex flex-col md:flex-row max-w-7xl mx-auto w-full gap-6 p-4 md:p-6 overflow-hidden">
        {/* Sidebar Navigation */}
        <aside className="no-print w-full md:w-64 flex-shrink-0">
          <nav className="space-y-1">
            {SECTIONS.map((s) => (
              <button
                key={s.id}
                onClick={() => setActiveTab(s.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-all ${
                  activeTab === s.id 
                    ? 'bg-indigo-50 text-indigo-700 shadow-sm border border-indigo-100' 
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                {s.icon}
                {s.label}
              </button>
            ))}
          </nav>

          <div className="mt-8 p-4 bg-slate-100 rounded-xl border border-slate-200">
            <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Trạng thái hoàn thành</h4>
            <div className="w-full bg-slate-200 rounded-full h-1.5 mb-2">
              <div className="bg-indigo-600 h-1.5 rounded-full" style={{ width: '45%' }}></div>
            </div>
            <p className="text-[10px] text-slate-500">Hoàn thành 45% nội dung báo cáo</p>
          </div>
        </aside>

        {/* Form Content Area */}
        <div className="no-print flex-1 overflow-y-auto pr-2 custom-scrollbar">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8">
            {activeTab === 'info' && (
              <div className="space-y-4">
                <SectionHeader title="Thông tin chung" description="Cung cấp các thông tin cơ bản về tác giả và sáng kiến." />
                <FormField label="Tên sáng kiến" value={data.title} onChange={(v) => handleUpdate('title', v)} placeholder="Ví dụ: Một số biện pháp giúp học sinh học tốt môn Toán lớp 3..." />
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <FormField label="Họ và tên người thực hiện" value={data.author} onChange={(v) => handleUpdate('author', v)} />
                  <FormField label="Đơn vị công tác" value={data.unit} onChange={(v) => handleUpdate('unit', v)} />
                </div>
                <FormField label="Cá nhân tổ chức phối hợp" value={data.collaborators} onChange={(v) => handleUpdate('collaborators', v)} />
                <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  <FormField label="Ngày" value={data.day} onChange={(v) => handleUpdate('day', v)} />
                  <FormField label="Tháng" value={data.month} onChange={(v) => handleUpdate('month', v)} />
                  <FormField label="Năm" value={data.year} onChange={(v) => handleUpdate('year', v)} />
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <FormField label="Từ ngày" value={data.startDate} onChange={(v) => handleUpdate('startDate', v)} />
                  <FormField label="Đến ngày" value={data.endDate} onChange={(v) => handleUpdate('endDate', v)} />
                </div>
              </div>
            )}

            {activeTab === 'problem' && (
              <div className="space-y-4">
                <SectionHeader title="I. Đặt vấn đề" description="Trình bày tính cấp thiết và lý do lựa chọn sáng kiến." />
                <FormField 
                  label="1. Tên sáng kiến hoặc giải pháp" 
                  value={data.problemStatement.initiativeName || data.title} 
                  onChange={(v) => handleUpdate('problemStatement.initiativeName', v)} 
                />
                <FormField 
                  label="2. Sự cần thiết, mục đích thực hiện (Lý do nghiên cứu)" 
                  type="textarea"
                  value={data.problemStatement.necessity} 
                  onChange={(v) => handleUpdate('problemStatement.necessity', v)} 
                  onAIGenerate={() => handleAIGenerate("Lý do nghiên cứu và tính cấp thiết của đề tài", "problemStatement.necessity")}
                  isGenerating={isGenerating === 'problemStatement.necessity'}
                />
              </div>
            )}

            {activeTab === 'content' && (
              <div className="space-y-4">
                <SectionHeader title="II. Nội dung sáng kiến" description="Trình bày thực trạng và các biện pháp giải quyết." />
                <h4 className="font-bold text-slate-700 text-sm">1. Thực trạng tại đơn vị:</h4>
                <div className="grid grid-cols-1 gap-4 ml-2 border-l-2 border-slate-100 pl-4">
                  <FormField 
                    label="a. Thuận lợi" 
                    type="textarea"
                    value={data.content.status.advantages} 
                    onChange={(v) => handleUpdate('content.status.advantages', v)} 
                    onAIGenerate={() => handleAIGenerate("Những thuận lợi của giáo viên và học sinh", "content.status.advantages")}
                    isGenerating={isGenerating === 'content.status.advantages'}
                  />
                  <FormField 
                    label="b. Khó khăn" 
                    type="textarea"
                    value={data.content.status.disadvantages} 
                    onChange={(v) => handleUpdate('content.status.disadvantages', v)} 
                    onAIGenerate={() => handleAIGenerate("Những khó khăn, tồn tại trong quá trình dạy học", "content.status.disadvantages")}
                    isGenerating={isGenerating === 'content.status.disadvantages'}
                  />
                </div>
                <FormField 
                  label="2. Nguyên nhân và hạn chế" 
                  type="textarea"
                  value={data.content.causes} 
                  onChange={(v) => handleUpdate('content.causes', v)} 
                  onAIGenerate={() => handleAIGenerate("Nguyên nhân của các hạn chế hiện nay", "content.causes")}
                  isGenerating={isGenerating === 'content.causes'}
                />
                <FormField 
                  label="3. Các biện pháp thực hiện" 
                  type="textarea"
                  value={data.content.solutions} 
                  onChange={(v) => handleUpdate('content.solutions', v)} 
                  onAIGenerate={() => handleAIGenerate("Các biện pháp cụ thể, sáng tạo để giải quyết vấn đề", "content.solutions")}
                  isGenerating={isGenerating === 'content.solutions'}
                />
              </div>
            )}

            {activeTab === 'evaluation' && (
              <div className="space-y-4">
                <SectionHeader title="III. Đánh giá tính mới & hiệu quả" description="Đánh giá kết quả đạt được sau khi áp dụng sáng kiến." />
                <FormField 
                  label="1. Tính mới" 
                  type="textarea"
                  value={data.evaluation.novelty} 
                  onChange={(v) => handleUpdate('evaluation.novelty', v)} 
                  onAIGenerate={() => handleAIGenerate("Tính mới và sự khác biệt của sáng kiến", "evaluation.novelty")}
                  isGenerating={isGenerating === 'evaluation.novelty'}
                />
                <FormField 
                  label="2. Tính hiệu quả và khả thi" 
                  type="textarea"
                  value={data.evaluation.efficiency} 
                  onChange={(v) => handleUpdate('evaluation.efficiency', v)} 
                  onAIGenerate={() => handleAIGenerate("Hiệu quả về định tính và định lượng sau khi áp dụng", "evaluation.efficiency")}
                  isGenerating={isGenerating === 'evaluation.efficiency'}
                />
                <FormField 
                  label="3. Phạm vi áp dụng" 
                  type="textarea"
                  value={data.evaluation.scope} 
                  onChange={(v) => handleUpdate('evaluation.scope', v)} 
                  onAIGenerate={() => handleAIGenerate("Khả năng nhân rộng và áp dụng tại các đơn vị khác", "evaluation.scope")}
                  isGenerating={isGenerating === 'evaluation.scope'}
                />
              </div>
            )}

            {activeTab === 'conclusion' && (
              <div className="space-y-4">
                <SectionHeader title="IV. Kết luận" description="Tóm tắt và đưa ra các kiến nghị." />
                <FormField 
                  label="Nội dung kết luận" 
                  type="textarea"
                  value={data.conclusion} 
                  onChange={(v) => handleUpdate('conclusion', v)} 
                  onAIGenerate={() => handleAIGenerate("Kết luận và lời khuyên cho giáo viên", "conclusion")}
                  isGenerating={isGenerating === 'conclusion'}
                />
              </div>
            )}

            {/* Navigation Buttons */}
            <div className="mt-10 pt-6 border-t border-slate-100 flex justify-between">
              <button
                disabled={activeTab === 'info'}
                onClick={() => {
                  const idx = SECTIONS.findIndex(s => s.id === activeTab);
                  if (idx > 0) setActiveTab(SECTIONS[idx-1].id);
                }}
                className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium text-slate-600 hover:bg-slate-50 disabled:opacity-50"
              >
                <ChevronLeft className="w-4 h-4" /> Quay lại
              </button>
              <button
                disabled={activeTab === 'conclusion'}
                onClick={() => {
                  const idx = SECTIONS.findIndex(s => s.id === activeTab);
                  if (idx < SECTIONS.length - 1) setActiveTab(SECTIONS[idx+1].id);
                }}
                className="flex items-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors shadow-sm"
              >
                Tiếp tục <ChevronRight className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Live Preview Area */}
        <div className="hidden lg:block w-[400px] xl:w-[500px] flex-shrink-0 no-print">
          <div className="sticky top-[88px] h-[calc(100vh-120px)] bg-slate-900 rounded-2xl p-4 overflow-y-auto custom-scrollbar">
            <div className="mb-4 flex justify-between items-center text-slate-300">
              <h3 className="text-xs font-bold uppercase tracking-widest">Xem trước tài liệu</h3>
              <span className="text-[10px] bg-slate-800 px-2 py-1 rounded">Chế độ Draft</span>
            </div>
            <div className="scale-[0.45] origin-top transform-gpu">
              <ReportPreview data={data} />
            </div>
          </div>
        </div>
      </main>

      {/* Actual Print Area (Hidden during UI interaction) */}
      <div className="hidden print:block">
        <ReportPreview data={data} />
      </div>

      <footer className="no-print bg-white border-t border-slate-200 py-4 px-6 text-center text-slate-500 text-xs mt-auto">
        &copy; {new Date().getFullYear()} Smart Initiative Pro. Được phát triển để hỗ trợ giáo dục Việt Nam.
      </footer>
    </div>
  );
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateSectionContent = async (sectionName: string, context: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Bạn là một chuyên gia giáo dục tại Việt Nam.
    Hãy viết nội dung cho phần "${sectionName}" dựa trên bối cảnh: "${context}".
    Yêu cầu: Văn phong sư phạm, chuyên nghiệp, thực tế.
    Kết quả trả về chỉ bao gồm nội dung văn bản.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
    });
    return response.text || "";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Lỗi kết nối AI.";
  }
};

export const generateFullReportAI = async (title: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `Bạn là một chuyên gia viết Sáng kiến kinh nghiệm (SKKN) đoạt giải cao tại Việt Nam. 
  Dựa trên tên sáng kiến: "${title}", hãy viết toàn bộ nội dung chi tiết cho báo cáo theo cấu trúc chuẩn.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            necessity: { type: Type.STRING, description: "Sự cần thiết, mục đích thực hiện" },
            advantages: { type: Type.STRING, description: "Thuận lợi" },
            disadvantages: { type: Type.STRING, description: "Khó khăn" },
            causes: { type: Type.STRING, description: "Nguyên nhân và hạn chế" },
            solutions: { type: Type.STRING, description: "Các biện pháp thực hiện (viết chi tiết ít nhất 3 biện pháp)" },
            novelty: { type: Type.STRING, description: "Tính mới" },
            efficiency: { type: Type.STRING, description: "Tính hiệu quả và khả thi" },
            scope: { type: Type.STRING, description: "Phạm vi áp dụng" },
            conclusion: { type: Type.STRING, description: "Kết luận" }
          },
          required: ["necessity", "advantages", "disadvantages", "causes", "solutions", "novelty", "efficiency", "scope", "conclusion"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Full AI Generation Error:", error);
    throw error;
  }
};

