import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateSectionContent = async (sectionName: string, context: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Bạn là một chuyên gia giáo dục tại Việt Nam.
    Hãy viết nội dung cho phần "${sectionName}" dựa trên bối cảnh: "${context}".
    Yêu cầu: Văn phong sư phạm, chuyên nghiệp, thực tế.
    Kết quả trả về chỉ bao gồm nội dung văn bản.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
    });
    return response.text || "";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Lỗi kết nối AI.";
  }
};

export const generateFullReportAI = async (title: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `Bạn là một chuyên gia viết Sáng kiến kinh nghiệm (SKKN) đoạt giải cao tại Việt Nam. 
  Dựa trên tên sáng kiến: "${title}", hãy thực hiện các bước sau:
  1. Lập kế hoạch chi tiết các bước triển khai.
  2. Soạn thảo toàn bộ nội dung báo cáo theo đúng cấu trúc chuyên nghiệp.

  Yêu cầu về nội dung:
  - Sự cần thiết: Phân tích sâu sắc tại sao cần sáng kiến này.
  - Thuận lợi/Khó khăn: Sát với thực tế giáo dục hiện nay.
  - Biện pháp: Đưa ra ít nhất 3-4 biện pháp cụ thể, có tính mới và sáng tạo.
  - Hiệu quả: Đánh giá rõ rệt sự thay đổi trước và sau khi áp dụng.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            necessity: { type: Type.STRING, description: "Sự cần thiết, mục đích thực hiện" },
            advantages: { type: Type.STRING, description: "Thuận lợi" },
            disadvantages: { type: Type.STRING, description: "Khó khăn" },
            causes: { type: Type.STRING, description: "Nguyên nhân và hạn chế" },
            solutions: { type: Type.STRING, description: "Các biện pháp thực hiện chi tiết" },
            novelty: { type: Type.STRING, description: "Tính mới" },
            efficiency: { type: Type.STRING, description: "Tính hiệu quả và khả thi" },
            scope: { type: Type.STRING, description: "Phạm vi áp dụng" },
            conclusion: { type: Type.STRING, description: "Kết luận và kiến nghị" }
          },
          required: ["necessity", "advantages", "disadvantages", "causes", "solutions", "novelty", "efficiency", "scope", "conclusion"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Full AI Generation Error:", error);
    throw error;
  }
};

