import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Tạo nội dung cho một phần đơn lẻ của báo cáo
 */
export const generateSectionContent = async (sectionName: string, context: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Bạn là một chuyên gia giáo dục tại Việt Nam, có kinh nghiệm viết sáng kiến kinh nghiệm đoạt giải cao.
    Hãy viết nội dung cho phần "${sectionName}" dựa trên bối cảnh: "${context}".

    Yêu cầu:
    1. Ngôn ngữ chuyên nghiệp, đúng văn phong sư phạm Việt Nam.
    2. Nội dung cụ thể, sáng tạo và có tính thực tiễn cao.
    3. Trình bày rõ ràng, mạch lạc.

    Kết quả trả về chỉ bao gồm nội dung văn bản cho phần này, không thêm lời dẫn.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
    });
    return response.text || "Không thể tạo nội dung, vui lòng thử lại.";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Lỗi kết nối AI. Vui lòng kiểm tra lại.";
  }
};

/**
 * Lập kế hoạch và soạn thảo toàn bộ nội dung báo cáo từ tên sáng kiến
 */
export const generateFullReportAI = async (title: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `Bạn là một chuyên gia tư vấn giáo dục cấp cao tại Việt Nam. 
  Dựa trên tên sáng kiến: "${title}", hãy lập kế hoạch chi tiết và soạn thảo toàn bộ nội dung cho báo cáo Sáng kiến kinh nghiệm.

  Yêu cầu chuyên môn:
  - Sự cần thiết: Phải nêu bật được lý do chọn đề tài, tính cấp thiết trong bối cảnh đổi mới giáo dục hiện nay.
  - Thực trạng: Phân tích khách quan các thuận lợi và khó khăn điển hình.
  - Biện pháp: Đưa ra ít nhất 3 biện pháp cụ thể, mang tính đột phá và có thể triển khai ngay.
  - Đánh giá: Phải có số liệu hoặc định hướng đánh giá tính mới và hiệu quả rõ rệt.
  - Kết luận: Tóm lược súc tích và đưa ra kiến nghị thực tế.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            necessity: { type: Type.STRING, description: "Sự cần thiết, mục đích thực hiện (Đặt vấn đề)" },
            advantages: { type: Type.STRING, description: "Các thuận lợi hiện có" },
            disadvantages: { type: Type.STRING, description: "Các khó khăn đang gặp phải" },
            causes: { type: Type.STRING, description: "Nguyên nhân của thực trạng" },
            solutions: { type: Type.STRING, description: "Các biện pháp thực hiện chi tiết và cụ thể" },
            novelty: { type: Type.STRING, description: "Tính mới của sáng kiến" },
            efficiency: { type: Type.STRING, description: "Tính hiệu quả và khả thi sau khi áp dụng" },
            scope: { type: Type.STRING, description: "Phạm vi áp dụng của sáng kiến" },
            conclusion: { type: Type.STRING, description: "Kết luận và các kiến nghị sư phạm" }
          },
          required: ["necessity", "advantages", "disadvantages", "causes", "solutions", "novelty", "efficiency", "scope", "conclusion"]
        }
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.error("Full AI Generation Error:", error);
    throw error;
  }
};

