  const handleFullAIGeneration = async () => {
    if (!data.title || data.title.trim().length < 10) {
      alert("Vui lòng nhập tên sáng kiến đầy đủ (ít nhất 10 ký tự) để AI có thể lập kế hoạch chính xác.");
