import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Tạo nội dung cho một phần đơn lẻ của báo cáo với độ chi tiết cao
 */
export const generateSectionContent = async (sectionName: string, context: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Bạn là một chuyên gia giáo dục xuất sắc tại Việt Nam.
    Hãy viết nội dung cực kỳ chi tiết, chuyên sâu cho phần "${sectionName}" của sáng kiến: "${context}".

    Yêu cầu:
    1. Văn phong sư phạm mẫu mực, lập luận sắc bén, giàu tính thực tiễn.
    2. Nếu là phần 'Giải pháp', hãy mô tả tỉ mỉ quy trình triển khai từng bước, các ví dụ minh họa cụ thể.
    3. Nếu là phần 'Đánh giá', hãy phân tích sâu sắc các chỉ số định lượng và định tính.
    4. Dung lượng: Viết thật dài, chi tiết, đảm bảo tính học thuật và thực hành.

    Kết quả trả về chỉ bao gồm nội dung văn bản.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });
    return response.text || "Không thể tạo nội dung, vui lòng thử lại.";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Lỗi kết nối AI. Vui lòng thử lại.";
  }
};

/**
 * Lập kế hoạch và soạn thảo toàn bộ nội dung báo cáo với yêu cầu dung lượng lớn (tương đương 12 trang)
 */
export const generateFullReportAI = async (title: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `Bạn là một chuyên gia viết Sáng kiến kinh nghiệm (SKKN) đoạt giải cấp Quốc gia. 
  Dựa trên tên đề tài: "${title}", hãy soạn thảo một bản báo cáo đầy đủ, chi tiết và cực kỳ chuyên sâu. 

  Mục tiêu: Nội dung phải đạt chất lượng chuyên môn cao, hướng tới dung lượng tương đương 12 trang giấy A4 khi trình bày đầy đủ.

  YÊU CẦU CHI TIẾT:
  1. PHẦN II (NỘI DUNG): 
     - Phân tích thực trạng: Không chỉ nêu khó khăn mà phải phân tích sâu xa nguyên nhân chủ quan, khách quan, tâm lý học sinh, điều kiện cơ sở vật chất.
     - Các biện pháp: Đây là phần trọng tâm. Hãy đưa ra ít nhất 4-5 biện pháp chiến lược. Mỗi biện pháp phải gồm: (1) Mục tiêu biện pháp, (2) Cách thức triển khai chi tiết từng bước, (3) Ví dụ minh họa thực tế, (4) Kết quả mong đợi của riêng biện pháp đó.
  2. PHẦN III (ĐÁNH GIÁ): 
     - Tính mới: Phải chỉ rõ điểm khác biệt so với các phương pháp truyền thống, tính sáng tạo trong việc vận dụng công nghệ hoặc học thuyết sư phạm mới.
     - Tính hiệu quả & Khả thi: Phân tích dựa trên các tiêu chí cụ thể (thái độ, năng lực, kết quả kiểm tra). Chứng minh bằng lập luận logic về việc tiết kiệm thời gian, công sức mà vẫn đạt hiệu quả cao.
     - Phạm vi áp dụng: Khả năng triển khai tại các khối lớp khác, các trường có điều kiện tương tự.
  3. PHẦN IV (KẾT LUẬN): Đúc kết giá trị cốt lõi và đề xuất các chính sách hỗ trợ từ phía nhà trường/ngành.

  Văn phong: Chuyên nghiệp, đúng quy định về ngôn ngữ hành chính - sư phạm Việt Nam.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            necessity: { type: Type.STRING, description: "Phần Đặt vấn đề cực kỳ chi tiết" },
            advantages: { type: Type.STRING, description: "Thuận lợi thực tế sâu sắc" },
            disadvantages: { type: Type.STRING, description: "Khó khăn và thách thức cụ thể" },
            causes: { type: Type.STRING, description: "Phân tích nguyên nhân đa chiều" },
            solutions: { type: Type.STRING, description: "Hệ thống các biện pháp thực hiện chi tiết (phần dài nhất)" },
            novelty: { type: Type.STRING, description: "Phân tích tính mới và tính sáng tạo đột phá" },
            efficiency: { type: Type.STRING, description: "Đánh giá chi tiết hiệu quả và tính khả thi" },
            scope: { type: Type.STRING, description: "Phạm vi áp dụng và khả năng nhân rộng" },
            conclusion: { type: Type.STRING, description: "Kết luận và kiến nghị sư phạm tầm vóc" }
          },
          required: ["necessity", "advantages", "disadvantages", "causes", "solutions", "novelty", "efficiency", "scope", "conclusion"]
        }
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.error("Full AI Generation Error:", error);
    throw error;
  }
};

