import React, { useState } from 'react';
import { 
  FileText, 
  Printer, 
  ChevronRight, 
  ChevronLeft, 
  Info, 
  HelpCircle,
  BarChart3,
  CheckCircle2,
  Sparkles,
  BrainCircuit,
  PenTool,
  Wand2,
  FileCode,
  Layout
} from 'lucide-react';
import { ReportData, ActiveSection } from './types';
import { FormField } from './components/FormField';
import { SectionHeader } from './components/SectionHeader';
import { ReportPreview } from './components/ReportPreview';
import { generateSectionContent, generateFullReportAI } from './services/geminiService';
import { exportToWord } from './services/wordExportService';

const INITIAL_DATA: ReportData = {
  location: 'Rạch Chèo',
  day: new Date().getDate().toString(),
  month: (new Date().getMonth() + 1).toString(),
  year: new Date().getFullYear().toString(),
  title: '',
  author: '',
  unit: '',
  collaborators: '',
  startDate: '',
  endDate: '',
  problemStatement: {
    initiativeName: '',
    necessity: '',
  },
  content: {
    status: {
      advantages: '',
      disadvantages: '',
    },
    causes: '',
    solutions: '',
  },
  evaluation: {
    novelty: '',
    efficiency: '',
    scope: '',
  },
  conclusion: '',
};

const SECTIONS: { id: ActiveSection; label: string; icon: React.ReactNode }[] = [
  { id: 'info', label: 'Trang bìa', icon: <Layout className="w-4 h-4" /> },
  { id: 'problem', label: 'Đặt vấn đề', icon: <HelpCircle className="w-4 h-4" /> },
  { id: 'content', label: 'Nội dung (P1)', icon: <FileText className="w-4 h-4" /> },
  { id: 'evaluation', label: 'Nội dung (P2)', icon: <BarChart3 className="w-4 h-4" /> },
  { id: 'conclusion', label: 'Kết luận', icon: <CheckCircle2 className="w-4 h-4" /> },
];

export default function App() {
  const [data, setData] = useState<ReportData>(INITIAL_DATA);
  const [activeTab, setActiveTab] = useState<ActiveSection>('info');
  const [isGeneratingField, setIsGeneratingField] = useState<string | null>(null);
  const [isFullGenerating, setIsFullGenerating] = useState(false);

  const handleUpdate = (path: string, value: string) => {
    setData(prev => {
      const newData = { ...prev };
      const keys = path.split('.');
      let current: any = newData;
      for (let i = 0; i < keys.length - 1; i++) {
        current = current[keys[i]];
      }
      current[keys[keys.length - 1]] = value;
      return newData;
    });
  };

  const handleFullAIGeneration = async () => {
    if (!data.title || data.title.trim().length < 10) {
      alert("Vui lòng nhập tên sáng kiến đầy đủ để AI có thể lập kế hoạch chính xác.");
      return;
    }

    try {
      setIsFullGenerating(true);
      const result = await generateFullReportAI(data.title);

      setData(prev => ({
        ...prev,
        problemStatement: { 
          ...prev.problemStatement, 
          initiativeName: data.title, 
          necessity: result.necessity 
        },
        content: {
          ...prev.content,
          status: { advantages: result.advantages, disadvantages: result.disadvantages },
          causes: result.causes,
          solutions: result.solutions
        },
        evaluation: {
          ...prev.evaluation,
          novelty: result.novelty,
          efficiency: result.efficiency,
          scope: result.scope
        },
        conclusion: result.conclusion
      }));

      setTimeout(() => {
        setActiveTab('problem');
        alert("🎉 AI đã soạn thảo xong bản thảo 12 trang! Hãy kiểm tra từng phần để tinh chỉnh nhé.");
      }, 800);
    } catch (error) {
      alert("Lỗi AI. Vui lòng thử lại.");
    } finally {
      setIsFullGenerating(false);
    }
  };

  const handleSingleAIGenerate = async (section: string, field: string) => {
    if (!data.title) {
      alert("Vui lòng điền tên sáng kiến trước.");
      return;
    }
    setIsGeneratingField(field);
    const content = await generateSectionContent(section, data.title);
    handleUpdate(field, content);
    setIsGeneratingField(null);
  };

  const handlePrint = () => window.print();

  const handleExportWord = async () => {
    try {
      await exportToWord(data);
    } catch (error) {
      alert("Lỗi xuất file. Hãy thử lại.");
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      {/* AI Loading Overlay */}
      {isFullGenerating && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[100] flex flex-col items-center justify-center text-white p-8">
          <BrainCircuit className="w-16 h-16 text-indigo-400 mb-6 animate-pulse" />
          <h2 className="text-3xl font-bold mb-4">Đang soạn thảo sáng kiến 12 trang...</h2>
          <p className="text-slate-400 max-w-md text-center">AI đang tổng hợp cơ sở lý luận, phân tích thực trạng và đề xuất các giải pháp sư phạm chi tiết.</p>
          <div className="mt-10 w-64 bg-slate-800 h-2 rounded-full overflow-hidden">
            <div className="bg-indigo-500 h-full animate-[loading_20s_linear_infinite]"></div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="no-print bg-white border-b px-6 py-4 sticky top-0 z-40">
        <div className="max-w-[1600px] mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <FileText className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-slate-900">SKKN <span className="text-indigo-600">SmartWriter</span></h1>
          </div>

          <div className="flex items-center gap-3">
            <button onClick={handleExportWord} className="flex items-center gap-2 bg-slate-100 text-slate-700 hover:bg-slate-200 px-5 py-2.5 rounded-xl text-sm font-bold transition-all border">
              <FileCode className="w-4 h-4" /> Tải file Word (Chuẩn 12 trang)
            </button>
            <button onClick={handlePrint} className="flex items-center gap-2 bg-indigo-600 text-white hover:bg-indigo-700 px-5 py-2.5 rounded-xl text-sm font-bold shadow-lg shadow-indigo-200 transition-all">
              <Printer className="w-4 h-4" /> In báo cáo
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 flex max-w-[1600px] mx-auto w-full overflow-hidden">
        {/* Navigation */}
        <aside className="no-print w-64 flex-shrink-0 p-6 border-r bg-white">
          <div className="space-y-2">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Cấu trúc các trang</p>
            {SECTIONS.map((s) => (
              <button
                key={s.id}
                onClick={() => setActiveTab(s.id)}
                className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl text-sm font-bold transition-all ${
                  activeTab === s.id 
                    ? 'bg-indigo-50 text-indigo-700 border-l-4 border-indigo-600' 
                    : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                {s.icon} {s.label}
              </button>
            ))}
          </div>
        </aside>

        {/* Editor */}
        <div className="no-print flex-1 overflow-y-auto p-10 bg-[#f8fafc]">
          <div className="max-w-3xl mx-auto">
            <div className="bg-white rounded-3xl shadow-sm border p-10">
              {activeTab === 'info' && (
                <div className="space-y-6">
                  <SectionHeader title="Trang 1: Thông tin định danh" description="Thiết lập các thông tin cơ bản cho trang bìa sáng kiến." />
                  <FormField 
                    label="Tên sáng kiến kinh nghiệm" 
                    value={data.title} 
                    onChange={(v) => handleUpdate('title', v)} 
                    placeholder="Nhập tên đề tài..." 
                  />

                  {data.title.length >= 10 && (
                    <button
                      onClick={handleFullAIGeneration}
                      className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white py-4 rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 mb-8"
                    >
                      <Sparkles className="w-4 h-4" /> TỰ ĐỘNG SOẠN THẢO 12 TRANG THEO ĐỀ TÀI NÀY
                    </button>
                  )}

                  <div className="grid grid-cols-2 gap-4 pt-6 border-t">
                    <FormField label="Người thực hiện" value={data.author} onChange={(v) => handleUpdate('author', v)} />
                    <FormField label="Đơn vị công tác" value={data.unit} onChange={(v) => handleUpdate('unit', v)} />
                    <FormField label="Địa điểm" value={data.location} onChange={(v) => handleUpdate('location', v)} />
                    <FormField label="Năm thực hiện" value={data.year} onChange={(v) => handleUpdate('year', v)} />
                  </div>
                  <FormField label="Cá nhân/Tổ chức phối hợp" value={data.collaborators} onChange={(v) => handleUpdate('collaborators', v)} />
                  <div className="grid grid-cols-2 gap-4">
                    <FormField label="Từ ngày" value={data.startDate} onChange={(v) => handleUpdate('startDate', v)} placeholder="DD/MM/YYYY" />
                    <FormField label="Đến ngày" value={data.endDate} onChange={(v) => handleUpdate('endDate', v)} placeholder="DD/MM/YYYY" />
                  </div>
                </div>
              )}

              {activeTab === 'problem' && (
                <div className="space-y-6">
                  <SectionHeader title="I. Đặt vấn đề" description="Phân tích tính cấp thiết và lý do chọn đề tài." />
                  <FormField 
                    label="Lý do chọn đề tài" 
                    type="textarea"
                    value={data.problemStatement.necessity} 
                    onChange={(v) => handleUpdate('problemStatement.necessity', v)} 
                    onAIGenerate={() => handleSingleAIGenerate("Lý do nghiên cứu cực kỳ chi tiết", "problemStatement.necessity")}
                    isGenerating={isGeneratingField === 'problemStatement.necessity'}
                  />
                </div>
              )}

              {activeTab === 'content' && (
                <div className="space-y-6">
                  <SectionHeader title="II. Nội dung sáng kiến (Phần thực trạng)" />
                  <FormField label="Thuận lợi" type="textarea" value={data.content.status.advantages} onChange={(v) => handleUpdate('content.status.advantages', v)} />
                  <FormField label="Khó khăn" type="textarea" value={data.content.status.disadvantages} onChange={(v) => handleUpdate('content.status.disadvantages', v)} />
                  <FormField label="Nguyên nhân" type="textarea" value={data.content.causes} onChange={(v) => handleUpdate('content.causes', v)} />
                </div>
              )}

              {activeTab === 'evaluation' && (
                <div className="space-y-6">
                  <SectionHeader title="II. Nội dung sáng kiến (Phần giải pháp)" />
                  <FormField 
                    label="Các biện pháp thực hiện (Trọng tâm của 12 trang)" 
                    type="textarea"
                    value={data.content.solutions} 
                    onChange={(v) => handleUpdate('content.solutions', v)} 
                    onAIGenerate={() => handleSingleAIGenerate("Hệ thống giải pháp sư phạm chi tiết", "content.solutions")}
                    isGenerating={isGeneratingField === 'content.solutions'}
                  />
                </div>
              )}

              {activeTab === 'conclusion' && (
                <div className="space-y-6">
                  <SectionHeader title="III & IV. Đánh giá & Kết luận" />
                  <FormField label="Tính mới & Hiệu quả" type="textarea" value={data.evaluation.efficiency} onChange={(v) => handleUpdate('evaluation.efficiency', v)} />
                  <FormField label="Nội dung kết luận" type="textarea" value={data.conclusion} onChange={(v) => handleUpdate('conclusion', v)} />
                </div>
              )}

              <div className="mt-12 flex justify-between">
                <button
                  disabled={activeTab === 'info'}
                  onClick={() => setActiveTab(SECTIONS[SECTIONS.findIndex(s => s.id === activeTab)-1].id)}
                  className="px-6 py-2.5 rounded-xl text-sm font-bold text-slate-400 hover:bg-slate-50 disabled:opacity-0"
                >
                  <ChevronLeft className="inline w-4 h-4 mr-1" /> Quay lại
                </button>
                <button
                  disabled={activeTab === 'conclusion'}
                  onClick={() => setActiveTab(SECTIONS[SECTIONS.findIndex(s => s.id === activeTab)+1].id)}
                  className="bg-indigo-50 text-indigo-700 px-8 py-2.5 rounded-xl text-sm font-bold hover:bg-indigo-100"
                >
                  Tiếp tục <ChevronRight className="inline w-4 h-4 ml-1" />
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Real-time A4 Preview */}
        <div className="hidden xl:block w-[500px] flex-shrink-0 no-print border-l bg-slate-100">
          <div className="h-full scale-[0.5] origin-top transform-gpu -mb-[100%]">
            <ReportPreview data={data} />
          </div>
        </div>
      </main>

      {/* Hidden Print Area */}
      <div className="hidden print:block">
        <ReportPreview data={data} />
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          100% { width: 100%; }
        }
        .custom-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
      `}</style>
    </div>
  );
}

import { 
  Document, 
  Packer, 
  Paragraph, 
  TextRun, 
  AlignmentType, 
  Table, 
  TableRow, 
  TableCell, 
  BorderStyle, 
  WidthType,
  PageBreak
} from "docx";
import FileSaver from "file-saver";
import { ReportData } from "../types";

const TIMES_NEW_ROMAN = "Times New Roman";
const FONT_SIZE_NORMAL = 28; // 14pt
const FONT_SIZE_TITLE = 40;  // 20pt cho trang bìa
const LINE_SPACING = 360;    // 1.5 lines

const MARGIN_TOP = 1134;    // 20mm
const MARGIN_BOTTOM = 1134; // 20mm
const MARGIN_LEFT = 1701;   // 30mm
const MARGIN_RIGHT = 850;   // 15mm

export const exportToWord = async (data: ReportData) => {
  const doc = new Document({
    styles: {
      default: {
        document: {
          run: { font: TIMES_NEW_ROMAN, size: FONT_SIZE_NORMAL },
          paragraph: {
            spacing: { line: LINE_SPACING, lineRule: "auto" as any, before: 120, after: 120 },
          },
        },
      },
    },
    sections: [
      {
        properties: {
          page: {
            margin: { top: MARGIN_TOP, bottom: MARGIN_BOTTOM, left: MARGIN_LEFT, right: MARGIN_RIGHT },
          },
        },
        children: [
          // TRANG BÌA
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: data.unit || "TÊN ĐƠN VỊ", bold: true, size: 26 })],
          }),
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: "⎯⎯⎯⎯⎯⎯⎯⎯⎯", size: 26 })],
          }),
          new Paragraph({ spacing: { before: 2000 } }),
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: "BÁO CÁO SÁNG KIẾN", bold: true, size: 48 })],
          }),
          new Paragraph({ spacing: { before: 1000 } }),
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [
              new TextRun({ text: "Tên sáng kiến: ", bold: true, italics: true }),
              new TextRun({ text: data.title.toUpperCase(), bold: true, size: 32 }),
            ],
          }),
          new Paragraph({ spacing: { before: 2000 } }),
          new Paragraph({
            children: [
              new TextRun({ text: "Họ và tên người thực hiện: ", bold: true }),
              new TextRun({ text: data.author }),
            ],
          }),
          new Paragraph({
            children: [
              new TextRun({ text: "Đơn vị công tác: ", bold: true }),
              new TextRun({ text: data.unit }),
            ],
          }),
          new Paragraph({
            children: [
              new TextRun({ text: "Cá nhân tổ chức phối hợp: ", bold: true }),
              new TextRun({ text: data.collaborators || "Không" }),
            ],
          }),
          new Paragraph({
            children: [
              new TextRun({ text: "Thời gian triển khai thực hiện: ", bold: true }),
              new TextRun({ text: `Từ ngày ${data.startDate} đến ngày ${data.endDate}` }),
            ],
          }),
          new Paragraph({ spacing: { before: 2000 } }),
          new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: `${data.location}, NĂM ${data.year}`, bold: true })],
          }),

          new Paragraph({ children: [new PageBreak()] }), // NGẮT TRANG SAU BÌA

          // NỘI DUNG BÁO CÁO
          new Table({
            width: { size: 100, type: WidthType.PERCENTAGE },
            borders: {
              top: { style: BorderStyle.NONE }, bottom: { style: BorderStyle.NONE },
              left: { style: BorderStyle.NONE }, right: { style: BorderStyle.NONE },
              insideHorizontal: { style: BorderStyle.NONE }, insideVertical: { style: BorderStyle.NONE },
            },
            rows: [
              new TableRow({
                children: [
                  new TableCell({
                    width: { size: 40, type: WidthType.PERCENTAGE },
                    children: [
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: data.unit, bold: true, size: 24 })] }),
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "⎯⎯⎯⎯⎯⎯⎯" })] }),
                    ]
                  }),
                  new TableCell({
                    width: { size: 60, type: WidthType.PERCENTAGE },
                    children: [
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM", bold: true, size: 24 })] }),
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "Độc lập - Tự do - Hạnh phúc", bold: true })] }),
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯" })] }),
                    ]
                  })
                ]
              })
            ]
          }),

          new Paragraph({
            alignment: AlignmentType.RIGHT,
            children: [new TextRun({ text: `${data.location}, ngày ${data.day} tháng ${data.month} năm ${data.year}`, italics: true })],
          }),

          new Paragraph({ spacing: { before: 600 }, alignment: AlignmentType.CENTER, children: [new TextRun({ text: "BÁO CÁO CHI TIẾT SÁNG KIẾN", bold: true, size: 32 })] }),

          new Paragraph({ children: [new TextRun({ text: "I. ĐẶT VẤN ĐỀ", bold: true })] }),
          ...data.problemStatement.necessity.split('\n').map(line => new Paragraph({ indent: { left: 720, firstLine: 432 }, alignment: AlignmentType.JUSTIFIED, children: [new TextRun({ text: line })] })),

          new Paragraph({ spacing: { before: 400 }, children: [new TextRun({ text: "II. NỘI DUNG SÁNG KIẾN", bold: true })] }),
          new Paragraph({ indent: { left: 400 }, children: [new TextRun({ text: "1. Thực trạng", bold: true })] }),
          ...data.content.status.advantages.split('\n').map(line => new Paragraph({ indent: { left: 720, firstLine: 432 }, alignment: AlignmentType.JUSTIFIED, children: [new TextRun({ text: line })] })),
          ...data.content.status.disadvantages.split('\n').map(line => new Paragraph({ indent: { left: 720, firstLine: 432 }, alignment: AlignmentType.JUSTIFIED, children: [new TextRun({ text: line })] })),

          new Paragraph({ indent: { left: 400 }, children: [new TextRun({ text: "2. Các giải pháp thực hiện", bold: true })] }),
          ...data.content.solutions.split('\n').map(line => new Paragraph({ indent: { left: 720, firstLine: 432 }, alignment: AlignmentType.JUSTIFIED, children: [new TextRun({ text: line })] })),

          new Paragraph({ spacing: { before: 800 } }),
          new Table({
            width: { size: 100, type: WidthType.PERCENTAGE },
            borders: { top: { style: BorderStyle.NONE }, bottom: { style: BorderStyle.NONE }, left: { style: BorderStyle.NONE }, right: { style: BorderStyle.NONE }, insideHorizontal: { style: BorderStyle.NONE }, insideVertical: { style: BorderStyle.NONE } },
            rows: [
              new TableRow({
                children: [
                  new TableCell({ children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "XÁC NHẬN CỦA ĐƠN VỊ", bold: true })] })] }),
                  new TableCell({ children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "NGƯỜI BÁO CÁO", bold: true })] }), new Paragraph({ spacing: { before: 1200 } }), new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: data.author, bold: true })] })] })
                ]
              })
            ]
          })
        ],
      },
    ],
  });

  const blob = await Packer.toBlob(doc);
  const fileName = `SKKN_12Trang_${data.author.replace(/\s/g, '_')}.docx`;

  if (FileSaver && typeof FileSaver.saveAs === 'function') {
    FileSaver.saveAs(blob, fileName);
  } else {
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
  }
};

export interface ReportData {
  day: string;
  month: string;
  year: string;
  title: string;
  author: string;
  unit: string;
  collaborators: string;
  startDate: string;
  endDate: string;
  problemStatement: {
    initiativeName: string;
    necessity: string;
  };
  content: {
    status: {
      advantages: string;
      disadvantages: string;
    };
    causes: string;
    solutions: string;
  };
  evaluation: {
    novelty: string;
    efficiency: string;
    scope: string;
  };
  conclusion: string;
}

export type ActiveSection = 'info' | 'problem' | 'content' | 'evaluation' | 'conclusion';

import React, { useState } from 'react';
import { 
  FileText, 
  Printer, 
  ChevronRight, 
  ChevronLeft, 
  HelpCircle,
  BarChart3,
  CheckCircle2,
  Sparkles,
  BrainCircuit,
  FileCode,
  UserCircle
} from 'lucide-react';
import { ReportData, ActiveSection } from './types';
import { FormField } from './components/FormField';
import { SectionHeader } from './components/SectionHeader';
import { ReportPreview } from './components/ReportPreview';
import { generateSectionContent, generateFullReportAI } from './services/geminiService';
import { exportToWord } from './services/wordExportService';

const INITIAL_DATA: ReportData = {
  day: new Date().getDate().toString(),
  month: (new Date().getMonth() + 1).toString(),
  year: new Date().getFullYear().toString(),
  title: '',
  author: '',
  unit: '',
  collaborators: '',
  startDate: '',
  endDate: '',
  problemStatement: {
    initiativeName: '',
    necessity: '',
  },
  content: {
    status: {
      advantages: '',
      disadvantages: '',
    },
    causes: '',
    solutions: '',
  },
  evaluation: {
    novelty: '',
    efficiency: '',
    scope: '',
  },
  conclusion: '',
};

const SECTIONS: { id: ActiveSection; label: string; icon: React.ReactNode }[] = [
  { id: 'info', label: 'Thông tin chung', icon: <UserCircle className="w-4 h-4" /> },
  { id: 'problem', label: 'Đặt vấn đề', icon: <HelpCircle className="w-4 h-4" /> },
  { id: 'content', label: 'Thực trạng', icon: <FileText className="w-4 h-4" /> },
  { id: 'evaluation', label: 'Giải pháp', icon: <BarChart3 className="w-4 h-4" /> },
  { id: 'conclusion', label: 'Đánh giá & KL', icon: <CheckCircle2 className="w-4 h-4" /> },
];

export default function App() {
  const [data, setData] = useState<ReportData>(INITIAL_DATA);
  const [activeTab, setActiveTab] = useState<ActiveSection>('info');
  const [isGeneratingField, setIsGeneratingField] = useState<string | null>(null);
  const [isFullGenerating, setIsFullGenerating] = useState(false);

  const handleUpdate = (path: string, value: string) => {
    setData(prev => {
      const newData = { ...prev };
      const keys = path.split('.');
      let current: any = newData;
      for (let i = 0; i < keys.length - 1; i++) {
        current = current[keys[i]];
      }
      current[keys[keys.length - 1]] = value;
      return newData;
    });
  };

  const handleFullAIGeneration = async () => {
    if (!data.title || data.title.trim().length < 5) {
      alert("Vui lòng nhập tên sáng kiến đầy đủ.");
      return;
    }

    try {
      setIsFullGenerating(true);
      const result = await generateFullReportAI(data.title);

      setData(prev => ({
        ...prev,
        problemStatement: { 
          ...prev.problemStatement, 
          initiativeName: data.title, 
          necessity: result.necessity 
        },
        content: {
          ...prev.content,
          status: { advantages: result.advantages, disadvantages: result.disadvantages },
          causes: result.causes,
          solutions: result.solutions
        },
        evaluation: {
          ...prev.evaluation,
          novelty: result.novelty,
          efficiency: result.efficiency,
          scope: result.scope
        },
        conclusion: result.conclusion
      }));

      setTimeout(() => {
        setActiveTab('problem');
        alert("🎉 AI đã soạn thảo xong bản thảo chi tiết! Hãy kiểm tra từng phần để tinh chỉnh nhé.");
      }, 500);
    } catch (error) {
      alert("Lỗi AI. Vui lòng thử lại.");
    } finally {
      setIsFullGenerating(false);
    }
  };

  const handleSingleAIGenerate = async (section: string, field: string) => {
    if (!data.title) {
      alert("Vui lòng điền tên sáng kiến trước.");
      return;
    }
    setIsGeneratingField(field);
    const content = await generateSectionContent(section, data.title);
    handleUpdate(field, content);
    setIsGeneratingField(null);
  };

  const handlePrint = () => window.print();

  const handleExportWord = async () => {
    try {
      await exportToWord(data);
    } catch (error) {
      alert("Lỗi xuất file. Hãy thử lại.");
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#eef2f3]">
      {/* AI Loading Overlay */}
      {isFullGenerating && (
        <div className="fixed inset-0 bg-emerald-950/95 backdrop-blur-lg z-[100] flex flex-col items-center justify-center text-white p-8">
          <BrainCircuit className="w-20 h-20 text-emerald-400 mb-6 animate-pulse" />
          <h2 className="text-4xl font-black mb-4">Đang soạn thảo 12 trang...</h2>
          <p className="text-emerald-200/80 max-w-lg text-center text-lg leading-relaxed">
            Hệ thống đang phân tích đề tài, lập cơ sở lý luận và đề xuất các biện pháp thực tiễn chuyên sâu cho sáng kiến của bạn.
          </p>
          <div className="mt-12 w-80 bg-emerald-900 h-3 rounded-full overflow-hidden shadow-inner">
            <div className="bg-emerald-400 h-full animate-[loading_25s_linear_infinite]"></div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="no-print bg-[#1a4d44] text-white shadow-xl px-8 py-5 sticky top-0 z-40">
        <div className="max-w-[1700px] mx-auto flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="bg-emerald-500 p-2.5 rounded-2xl shadow-lg">
              <FileText className="w-7 h-7 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tight">SKKN <span className="text-emerald-400">ProWriter</span></h1>
              <p className="text-xs text-emerald-200/60 font-medium uppercase tracking-widest">Hỗ trợ giáo viên sáng tạo</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button onClick={handleExportWord} className="flex items-center gap-2 bg-emerald-700/50 hover:bg-emerald-700 text-white px-6 py-3 rounded-2xl text-sm font-bold transition-all border border-emerald-600/50">
              <FileCode className="w-4 h-4" /> Xuất Word (12 Trang)
            </button>
            <button onClick={handlePrint} className="flex items-center gap-2 bg-emerald-500 text-white hover:bg-emerald-400 px-6 py-3 rounded-2xl text-sm font-bold shadow-lg shadow-emerald-900/40 transition-all active:scale-95">
              <Printer className="w-4 h-4" /> In nhanh
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 flex max-w-[1700px] mx-auto w-full overflow-hidden shadow-2xl my-4 rounded-3xl bg-white border border-slate-200">
        {/* Navigation Sidebar */}
        <aside className="no-print w-72 flex-shrink-0 p-8 border-r bg-slate-50 flex flex-col">
          <div className="flex-1 space-y-3">
            <p className="text-[11pt] font-black text-slate-400 uppercase tracking-widest mb-6">Danh mục nội dung</p>
            {SECTIONS.map((s) => (
              <button
                key={s.id}
                onClick={() => setActiveTab(s.id)}
                className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-[11pt] font-bold transition-all ${
                  activeTab === s.id 
                    ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-100' 
                    : 'text-slate-600 hover:bg-white hover:shadow-sm'
                }`}
              >
                {s.icon} {s.label}
              </button>
            ))}
          </div>

          <div className="mt-auto p-4 bg-emerald-50 rounded-2xl border border-emerald-100">
            <p className="text-xs text-emerald-700 font-bold mb-2">Mẹo viết tốt:</p>
            <p className="text-[10pt] text-emerald-800 leading-snug">Hãy cung cấp tên đề tài thật chi tiết để AI hiểu rõ bối cảnh lớp học của bạn.</p>
          </div>
        </aside>

        {/* Content Editor */}
        <div className="no-print flex-1 overflow-y-auto p-12 bg-white">
          <div className="max-w-4xl mx-auto">
            {activeTab === 'info' && (
              <div className="space-y-8 animate-in fade-in duration-500">
                <SectionHeader title="Thông tin định danh sáng kiến" description="Nhập thông tin xuất hiện ở đầu trang 1 của báo cáo." />
                <FormField 
                  label="Tên sáng kiến kinh nghiệm" 
                  value={data.title} 
                  onChange={(v) => handleUpdate('title', v)} 
                  placeholder="Ví dụ: Nâng cao năng lực đọc hiểu cho học sinh lớp 3 qua phương pháp thảo luận nhóm..." 
                />

                {data.title.length >= 8 && (
                  <button
                    onClick={handleFullAIGeneration}
