                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "TRỰC TIẾP", bold: true })] }),
                    ]
                  }),
                  new TableCell({
                    width: { size: 50, type: WidthType.PERCENTAGE },
                    children: [
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "NGƯỜI BÁO CÁO", bold: true })] }),
                      new Paragraph({ spacing: { before: 1200 } }),
                      new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: data.author, bold: true })] }),
                    ]
                  })
                ]
              })
            ]
          })
        ],
      },
    ],
  });

  const blob = await Packer.toBlob(doc);
  const fileName = `SKKN_${data.author.replace(/\s/g, '_') || 'Bao_Cao'}.docx`;

  try {
    if (FileSaver && typeof FileSaver.saveAs === 'function') {
      FileSaver.saveAs(blob, fileName);
    } else {
      throw new Error("FileSaver is not available");
    }
  } catch (error) {
    console.warn("Falling back to standard download link...");
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    link.click();
    window.URL.revokeObjectURL(url);
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Tạo nội dung cho một phần đơn lẻ của báo cáo với độ chi tiết cực cao
 */
export const generateSectionContent = async (sectionName: string, context: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `
    Bạn là một chuyên gia giáo dục bậc cao tại Việt Nam, nổi tiếng với các bản Sáng kiến kinh nghiệm (SKKN) đạt giải đặc biệt.
    Hãy viết nội dung cho phần "${sectionName}" của đề tài: "${context}".

    YÊU CẦU ĐẶC BIỆT VỀ TRÌNH BÀY:
    1. Viết theo phong cách mỗi câu là một ý hoàn chỉnh.
    2. Sau mỗi dấu chấm câu, phải là một ý tưởng mới để người dùng có thể dễ dàng xuống dòng.
    3. Nội dung phải cực kỳ dài, chi tiết (mục tiêu 12 trang cho toàn bộ báo cáo).
    4. Lập luận đa chiều, sử dụng thuật ngữ chuyên môn giáo dục chuẩn xác.

    Hãy viết thật dài, đảm bảo nội dung sâu sắc và thuyết phục tuyệt đối.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });
    return response.text || "Không thể tạo nội dung, vui lòng thử lại.";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Lỗi kết nối AI. Vui lòng thử lại.";
  }
};

/**
 * Lập kế hoạch và soạn thảo toàn bộ báo cáo dung lượng lớn (mục tiêu 12 trang A4)
 */
export const generateFullReportAI = async (title: string) => {
  const model = 'gemini-3-pro-preview';

  const prompt = `Bạn là một tác giả SKKN chuyên nghiệp cấp Quốc gia. Hãy soạn thảo báo cáo chi tiết cho đề tài: "${title}".

  QUY ĐỊNH VỀ DUNG LƯỢNG: Bản báo cáo này cần đạt độ dài tương đương 12 trang A4.

  YÊU CẦU CẤU TRÚC VĂN BẢN:
  - Hãy viết văn bản dưới dạng các câu đơn hoặc câu ghép ngắn.
  - Sau mỗi dấu chấm kết thúc câu, hãy đảm bảo đó là một thông tin độc lập.
  - TRÁNH viết các đoạn văn dài dằng dặc không có điểm dừng.

  YÊU CẦU NỘI DUNG TỪNG PHẦN:
  1. PHẦN I (ĐẶT VẤN ĐỀ): Phân tích tầm quan trọng của giáo dục, sự cần thiết của đề tài.
  2. PHẦN II (NỘI DUNG):
     - Thực trạng: Thuận lợi, khó khăn, bảng số liệu giả định.
     - Biện pháp: Mô tả ít nhất 5-7 biện pháp chiến lược cực kỳ chi tiết.
  3. PHẦN III (ĐÁNH GIÁ): Tính mới, tính hiệu quả, phạm vi áp dụng.
  4. PHẦN IV (KẾT LUẬN): Bài học kinh nghiệm và đề xuất.

  LƯU Ý: Hãy viết mỗi phần thật dài và đầy đủ nhất có thể.`;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            necessity: { type: Type.STRING, description: "Phần Đặt vấn đề" },
            advantages: { type: Type.STRING, description: "Thuận lợi" },
            disadvantages: { type: Type.STRING, description: "Khó khăn" },
            causes: { type: Type.STRING, description: "Nguyên nhân" },
            solutions: { type: Type.STRING, description: "Hệ thống các biện pháp thực hiện" },
            novelty: { type: Type.STRING, description: "Tính mới" },
            efficiency: { type: Type.STRING, description: "Tính hiệu quả" },
            scope: { type: Type.STRING, description: "Phạm vi áp dụng" },
            conclusion: { type: Type.STRING, description: "Kết luận" }
          },
          required: ["necessity", "advantages", "disadvantages", "causes", "solutions", "novelty", "efficiency", "scope", "conclusion"]
        }
      }
    });

    const text = response.text || "{}";
    return JSON.parse(text);
  } catch (error) {
    console.error("Full AI Generation Error:", error);
    throw error;
  }
};

import { 
