// Hàm hỗ trợ tách văn bản thành từng câu để xuất thành từng đoạn văn trong Word
const splitToSentences = (text: string) => {
  if (!text) return [];
  return text.split(/(?<=[.!?])\s+/).filter(s => s.trim().length > 0);
};

