      <Page pageNumber={4}>
        <h3 className="font-bold uppercase mb-4">III. ĐÁNH GIÁ & KẾT LUẬN</h3>
        <p className="font-bold mb-1">1. Tính mới:</p>
        {renderText(data.evaluation.novelty)}
        <p className="font-bold mt-4 mb-1">2. Hiệu quả:</p>
        {renderText(data.evaluation.efficiency)}

        <h3 className="font-bold uppercase mt-8 mb-2">IV. KẾT LUẬN</h3>
        {renderText(data.conclusion)}

        <div className="flex justify-between text-center mt-16">
          <div className="w-1/2 font-bold uppercase">XÁC NHẬN ĐƠN VỊ</div>
          <div className="w-1/2">
            <p className="font-bold uppercase">NGƯỜI BÁO CÁO</p>
            <div className="h-20"></div>
            <p className="font-bold underline uppercase">{data.author}</p>
          </div>
        </div>
      </Page>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  FileText, Printer, ChevronRight, ChevronLeft, HelpCircle, 
  BarChart3, CheckCircle2, Sparkles, BrainCircuit, FileCode, UserCircle 
} from 'lucide-react';
import { ReportData, ActiveSection } from './types';
import { FormField } from './components/FormField';
import { SectionHeader } from './components/SectionHeader';
import { ReportPreview } from './components/ReportPreview';
import { generateSectionContent, generateFullReportAI } from './services/geminiService';
import { exportToWord } from './services/wordExportService';

const INITIAL_DATA: ReportData = {
  title: '', author: '', unit: '', collaborators: '', startDate: '', endDate: '',
  problemStatement: { initiativeName: '', necessity: '' },
  content: { status: { advantages: '', disadvantages: '' }, causes: '', solutions: '' },
  evaluation: { novelty: '', efficiency: '', scope: '' },
  conclusion: '',
};

export default function App() {
  const [data, setData] = useState<ReportData>(INITIAL_DATA);
  const [activeTab, setActiveTab] = useState<ActiveSection>('info');
  const [isFullGenerating, setIsFullGenerating] = useState(false);

  const handleUpdate = (path: string, value: string) => {
    setData(prev => {
      const newData = { ...prev };
      const keys = path.split('.');
      let current: any = newData;
      for (let i = 0; i < keys.length - 1; i++) current = current[keys[i]];
      current[keys[keys.length - 1]] = value;
      return newData;
    });
  };

  const handleFullAIGeneration = async () => {
    if (!data.title) return alert("Nhập tên sáng kiến!");
    setIsFullGenerating(true);
    try {
      const res = await generateFullReportAI(data.title);
      setData(prev => ({
        ...prev,
        problemStatement: { ...prev.problemStatement, necessity: res.necessity },
        content: { ...prev.content, status: { advantages: res.advantages, disadvantages: res.disadvantages }, causes: res.causes, solutions: res.solutions },
        evaluation: { novelty: res.novelty, efficiency: res.efficiency, scope: res.scope },
        conclusion: res.conclusion
      }));
      setActiveTab('problem');
    } catch (e) { alert("Lỗi AI."); }
    finally { setIsFullGenerating(false); }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#f1f5f9]">
      {isFullGenerating && (
        <div className="fixed inset-0 bg-[#064e3b]/95 z-[100] flex flex-col items-center justify-center text-white">
          <BrainCircuit className="w-20 h-20 text-emerald-400 animate-pulse mb-4" />
          <h2 className="text-3xl font-bold">ĐANG SOẠN THẢO SKKN 4.0...</h2>
          <p className="mt-2 text-emerald-200">Phát triển bởi: BÙI VĂN ĐẠT</p>
        </div>
      )}

      <header className="bg-[#1a4d44] text-white px-8 py-4 flex justify-between items-center shadow-lg">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-xl"><FileText /></div>
          <h1 className="text-xl font-black">SÁNG KIẾN KINH NGHIỆM PRO</h1>
        </div>
        <div className="flex gap-3">
          <button onClick={() => exportToWord(data)} className="bg-emerald-700 hover:bg-emerald-600 px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-bold border border-emerald-500">
            <FileCode size={18} /> Xuất Word (Chuẩn)
          </button>
          <button onClick={() => window.print()} className="bg-emerald-500 hover:bg-emerald-400 px-4 py-2 rounded-lg flex items-center gap-2 text-sm font-bold">
            <Printer size={18} /> In nhanh
          </button>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-64 bg-white border-r p-6 no-print">
          <div className="space-y-2">
            {[
              { id: 'info', label: 'Thông tin chung', icon: <UserCircle size={18} /> },
              { id: 'problem', label: 'Đặt vấn đề', icon: <HelpCircle size={18} /> },
              { id: 'content', label: 'Thực trạng', icon: <FileText size={18} /> },
              { id: 'evaluation', label: 'Giải pháp', icon: <BarChart3 size={18} /> },
              { id: 'conclusion', label: 'Kết luận', icon: <CheckCircle2 size={18} /> },
            ].map(s => (
              <button key={s.id} onClick={() => setActiveTab(s.id as any)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all ${activeTab === s.id ? 'bg-emerald-600 text-white shadow-md' : 'text-slate-600 hover:bg-emerald-50'}`}>
                {s.icon} {s.label}
              </button>
            ))}
          </div>
        </aside>

        <div className="flex-1 overflow-y-auto p-10 no-print">
          <div className="max-w-3xl mx-auto bg-white p-10 rounded-3xl shadow-sm border border-slate-200">
            {activeTab === 'info' && (
              <div className="space-y-6">
                <SectionHeader title="Thông tin định danh" />
                <FormField label="Tên sáng kiến" value={data.title} onChange={v => handleUpdate('title', v)} placeholder="Ví dụ: Một số biện pháp..." />
                <button onClick={handleFullAIGeneration} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black flex justify-center gap-2 hover:bg-emerald-700 shadow-lg active:scale-95 transition-all">
                  <Sparkles size={20} /> TỰ ĐỘNG SOẠN THẢO TOÀN BỘ
                </button>
                <div className="grid grid-cols-2 gap-4">
                  <FormField label="Người thực hiện" value={data.author} onChange={v => handleUpdate('author', v)} />
                  <FormField label="Đơn vị" value={data.unit} onChange={v => handleUpdate('unit', v)} />
                </div>
                <FormField label="Cá nhân phối hợp" value={data.collaborators} onChange={v => handleUpdate('collaborators', v)} />
                <div className="grid grid-cols-2 gap-4">
                  <FormField label="Từ ngày" value={data.startDate} onChange={v => handleUpdate('startDate', v)} />
                  <FormField label="Đến ngày" value={data.endDate} onChange={v => handleUpdate('endDate', v)} />
                </div>
              </div>
            )}
            {activeTab === 'problem' && (
              <FormField label="Lý do chọn đề tài" type="textarea" value={data.problemStatement.necessity} onChange={v => handleUpdate('problemStatement.necessity', v)} />
            )}
            {activeTab === 'content' && (
              <div className="space-y-4">
                <FormField label="Thuận lợi" type="textarea" value={data.content.status.advantages} onChange={v => handleUpdate('content.status.advantages', v)} />
                <FormField label="Khó khăn" type="textarea" value={data.content.status.disadvantages} onChange={v => handleUpdate('content.status.disadvantages', v)} />
                <FormField label="Nguyên nhân" type="textarea" value={data.content.causes} onChange={v => handleUpdate('content.causes', v)} />
              </div>
            )}
            {activeTab === 'evaluation' && (
              <FormField label="Các biện pháp thực hiện" type="textarea" value={data.content.solutions} onChange={v => handleUpdate('content.solutions', v)} />
            )}
            {activeTab === 'conclusion' && (
              <div className="space-y-4">
                <FormField label="Tính mới & Hiệu quả" type="textarea" value={data.evaluation.efficiency} onChange={v => handleUpdate('evaluation.efficiency', v)} />
                <FormField label="Kết luận" type="textarea" value={data.conclusion} onChange={v => handleUpdate('conclusion', v)} />
              </div>
            )}
          </div>
        </div>

        <div className="hidden xl:block w-[500px] bg-slate-200 border-l overflow-hidden no-print">
          <div className="scale-[0.45] origin-top">
            <ReportPreview data={data} />
          </div>
        </div>
      </main>

      <div className="hidden print:block"><ReportPreview data={data} /></div>
    </div>
  );
}

import { 
  Document, Packer, Paragraph, TextRun, AlignmentType, 
  Table, TableRow, TableCell, BorderStyle, WidthType 
} from "docx";
import FileSaver from "file-saver";
import { ReportData } from "../types";

const TIMES = "Times New Roman";
const SIZE = 28; // 14pt
const LINE = 360;

const splitToSentences = (text: string) => {
  if (!text) return [];
  return text.split(/(?<=[.!?])\s+/).filter(s => s.trim().length > 0);
};

const renderLines = (text: string, indent: number = 720) => {
  return splitToSentences(text).map(s => new Paragraph({
    indent: { left: indent, firstLine: 432 },
    alignment: AlignmentType.JUSTIFIED,
    children: [new TextRun({ text: s, font: TIMES, size: SIZE })]
  }));
};

export const exportToWord = async (data: ReportData) => {
  const doc = new Document({
    sections: [{
      properties: { page: { margin: { top: 1134, bottom: 1134, left: 1701, right: 850 } } },
      children: [
        new Table({
          width: { size: 100, type: WidthType.PERCENTAGE },
          borders: { top: {style: BorderStyle.NONE}, bottom: {style: BorderStyle.NONE}, left: {style: BorderStyle.NONE}, right: {style: BorderStyle.NONE}, insideHorizontal: {style: BorderStyle.NONE}, insideVertical: {style: BorderStyle.NONE} },
          rows: [new TableRow({ children: [
            new TableCell({ children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: data.unit || "TÊN ĐƠN VỊ", bold: true, font: TIMES, size: 26 })] }), new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "⎯⎯⎯⎯⎯⎯⎯⎯⎯" })] })] }),
            new TableCell({ children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "CỘNG HÒA XÃ HỘI CHỦ NGHĨA VIỆT NAM", bold: true, font: TIMES, size: 26 })] }), new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "Độc lập - Tự do - Hạnh phúc", bold: true, font: TIMES, size: 28 })] }), new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯⎯" })] })] })
          ]})]
        }),

        new Paragraph({ spacing: { before: 400 }, children: [new TextRun({ text: `Tên sáng kiến: ${data.title.toUpperCase()}`, bold: true, font: TIMES, size: SIZE })] }),
        new Paragraph({ children: [new TextRun({ text: `Họ và tên người thực hiện: ${data.author}`, font: TIMES, size: SIZE })] }),
        new Paragraph({ children: [new TextRun({ text: `Đơn vị công tác: ${data.unit}`, font: TIMES, size: SIZE })] }),
        new Paragraph({ children: [new TextRun({ text: `Thời gian triển khai: Từ ${data.startDate} đến ${data.endDate}`, font: TIMES, size: SIZE })] }),

        new Paragraph({ spacing: { before: 600 }, alignment: AlignmentType.CENTER, children: [new TextRun({ text: "BÁO CÁO SÁNG KIẾN", bold: true, font: TIMES, size: 36 })] }),

        new Paragraph({ spacing: { before: 300 }, children: [new TextRun({ text: "I. ĐẶT VẤN ĐỀ", bold: true, font: TIMES, size: SIZE })] }),
        ...renderLines(data.problemStatement.necessity),

        new Paragraph({ spacing: { before: 400 }, children: [new TextRun({ text: "II. NỘI DUNG SÁNG KIẾN", bold: true, font: TIMES, size: SIZE })] }),
        new Paragraph({ indent: {left: 400}, children: [new TextRun({ text: "1. Thực trạng", bold: true, font: TIMES, size: SIZE })] }),
        ...renderLines(data.content.status.advantages),
        ...renderLines(data.content.status.disadvantages),
        new Paragraph({ indent: {left: 400}, children: [new TextRun({ text: "2. Giải pháp thực hiện", bold: true, font: TIMES, size: SIZE })] }),
        ...renderLines(data.content.solutions),

        new Paragraph({ spacing: { before: 400 }, children: [new TextRun({ text: "III. ĐÁNH GIÁ & KẾT LUẬN", bold: true, font: TIMES, size: SIZE })] }),
        ...renderLines(data.evaluation.efficiency),
        ...renderLines(data.conclusion),

        new Paragraph({ spacing: { before: 1000 } }),
        new Table({
          width: { size: 100, type: WidthType.PERCENTAGE },
          borders: { top: {style: BorderStyle.NONE}, bottom: {style: BorderStyle.NONE}, left: {style: BorderStyle.NONE}, right: {style: BorderStyle.NONE}, insideHorizontal: {style: BorderStyle.NONE}, insideVertical: {style: BorderStyle.NONE} },
          rows: [new TableRow({ children: [
            new TableCell({ children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "XÁC NHẬN CỦA ĐƠN VỊ", bold: true, font: TIMES, size: SIZE })] })] }),
            new TableCell({ children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "NGƯỜI BÁO CÁO", bold: true, font: TIMES, size: SIZE })] }), new Paragraph({ spacing: {before: 1200} }), new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: data.author.toUpperCase(), bold: true, font: TIMES, size: SIZE })] })] })
          ]})]
        })
      ]
    }]
  });

  const blob = await Packer.toBlob(doc);
  FileSaver.saveAs(blob, `SKKN_${data.author || 'Bao_Cao'}.docx`);
};
